import React, { useEffect, useState } from "react";
import axios from "axios";

const Table = ({ title, columns, data }) => {
  if (!data || data.length === 0) {
    return (
      <div className="bg-white rounded-xl shadow p-4 text-center text-gray-500 italic">
        Không có dữ liệu
      </div>
    );
  }

  return (
    <div className="bg-white rounded-xl shadow overflow-hidden mb-8">
      <h2 className="text-lg font-semibold bg-blue-600 text-white px-4 py-2">
        {title}
      </h2>
      <table className="w-full text-sm text-left">
        <thead className="bg-gray-100 border-b">
          <tr>
            {columns.map((col) => (
              <th key={col.key} className="px-4 py-2 font-medium text-gray-700">
                {col.label}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {data.map((row, idx) => (
            <tr
              key={idx}
              className={`border-b hover:bg-blue-50 ${
                idx % 2 === 0 ? "bg-gray-50" : "bg-white"
              }`}
            >
              {columns.map((col) => (
                <td key={col.key} className="px-4 py-2 text-gray-800">
                  {row[col.key]}
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

const Report = () => {
  const [monthlyRevenue, setMonthlyRevenue] = useState([]);
  const [yearlyRevenue, setYearlyRevenue] = useState([]);
  const [topCustomers, setTopCustomers] = useState([]);
  const [roomUsage, setRoomUsage] = useState([]);

  useEffect(() => {
    axios.get("http://localhost:3001/report/monthly").then((res) => setMonthlyRevenue(res.data));
    axios.get("http://localhost:3001/report/yearly").then((res) => setYearlyRevenue(res.data));
    axios.get("http://localhost:3001/report/topcustomers").then((res) => setTopCustomers(res.data));
    axios.get("http://localhost:3001/report/roomusage").then((res) => setRoomUsage(res.data));
  }, []);

  return (
    <div className="p-6 bg-gray-100 min-h-screen">
      <h1 className="text-2xl font-bold text-gray-800 mb-6">Báo cáo thống kê</h1>

      <Table
        title="Doanh thu theo tháng"
        columns={[
          { key: "Thang", label: "Tháng" },
          { key: "TongDoanhThu", label: "Tổng doanh thu" },
        ]}
        data={monthlyRevenue}
      />

      <Table
        title="Doanh thu theo năm"
        columns={[
          { key: "Nam", label: "Năm" },
          { key: "TongDoanhThu", label: "Tổng doanh thu" },
        ]}
        data={yearlyRevenue}
      />

      <Table
        title="Khách hàng tiêu biểu"
        columns={[
          { key: "TenKH", label: "Tên khách hàng" },
          { key: "TongChiTieu", label: "Tổng chi tiêu" },
        ]}
        data={topCustomers}
      />

      <Table
        title="Tần suất sử dụng phòng"
        columns={[
          { key: "PhongSo", label: "Phòng số" },
          { key: "SoLanThue", label: "Số lần thuê" },
        ]}
        data={roomUsage}
      />
    </div>
  );
};

export default Report;
